function i(t,r=1){return`${(t*100).toFixed(r)}%`}function a(t,r=4){return`$${t.toFixed(r)}`}function c(t){return t>=1e6?`${(t/1e6).toFixed(1)}M`:t>=1e3?`${(t/1e3).toFixed(1)}K`:String(t)}function u(t){if(!t)return"";const r=Date.now()-new Date(t).getTime(),n=Math.floor(r/1e3);if(n<60)return`${n}s ago`;const o=Math.floor(n/60);if(o<60)return`${o}m ago`;const e=Math.floor(o/60);return e<24?`${e}h ago`:`${Math.floor(e/24)}d ago`}export{c,i as p,u as r,a as u};
